@every(minutes=24 * 60)
def on_start(self):
    self.crawl('https://www.zhihu.com/', cookies = cookies, headers=hearders, callback=self.index_page, fetch_type='js')

@config(age=10 * 24 * 60 * 60)
def index_page(self, response):
    for each in response.doc('a[href^="http"]').items():
        self.crawl(each.attr.href, cookies = cookies, headers=headers, callback=self.detail_page, fetch_type='js')
            
@config(priority=2)
def detail_page(self, response):
    return {
        "url": response.url
    }`

But I am still curious about the difference between putting headers in the crawl_config and putting them in the self.crawl function..

