def make_ggnvp(f, g=lambda x: 1./2*np.dot(x, x))
    def ggnvp(x):
        f_vjp, f_x = make_vjp(f)(x)
        g_hvp, grad_g_x = make_vjp(grad(g))(f_x)
        f_vjp_vjp, _ = make_vjp(f_vjp)(np.zeros_like(grad_g_x))
        return lambda v: f_vjp(g_hvp(f_vjp_vjp(v)))
